l([Conceded]   ,0))[Conceded]        ,sum(isnull([InProgress] ,0))[InProgress]        ,sum(isnull([Win]     ,0))[Win]        ,sum(isnull([ShortSided] ,0))[ShortSided]  FROM    [SSRS].[CountyCricketBoard_2022Season]  Group by [YEAR_of_Fixture]   )A            